const response = $input.first().json;
const content = response.content?.[0]?.text || '[]';
let findings;
try {
  const jsonMatch = content.match(/\[.*\]/s);
  findings = JSON.parse(jsonMatch[0]);
} catch(e) {
  return [{ json: { findings_found: 0 } }];
}
return findings.map(f => ({ json: f }));
